INSERT INTO casto_team_members (id, name, role, focus_modules, responsibilities) VALUES
('rana', 'Rana', 'Event Lead', '["venue","schedule","report"]', 'Owns the venue floor plan and booth assignments, builds the event-day schedule, and compiles the post-event report. Final point of contact for anything not covered by another module.'),
('prithba', 'Prithba', 'Logistics & Equipment', '["equipment","requirements"]', 'Handles all equipment requests (tables, chairs, power, screens) and special requirements raised by companies (accessibility, AV, custom setups).'),
('aseel', 'Aseel', 'Branding & Media', '["banners"]', 'Tracks every company\'s banner and branding assets from submission through printing to placement on-site.'),
('maha', 'Maha', 'Attendance & Check-in', '["attendance","delegates"]', 'Runs check-in on event day (booth QR scans and student check-in) and manages the company delegate list and badge printing.'),
('yousef', 'Yousef', 'Access & Passes', '["passes"]', 'Issues and manages entry and parking access passes for every company delegate, including parking slot assignments.');
